<?php namespace App\Repositories\Certificate;use App\Repositories\BaseRepository;use App\Models\Certificate\Certificate;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class CertificateRepository extends BaseRepository{    public function __construct(Certificate $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findByCertificateType(int $certificateTypeId): Collection    {        return $this->findByField('certificate_type_id', $certificateTypeId);    }    public function findByEmployee(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('issue_date', [$startDate, $endDate])->get();    }    public function getPendingCertificates(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function issueCertificate(int $id, ?string $issuedBy = null): bool    {        $data = ['status' => 'issued', 'issue_date' => now()];        if ($issuedBy) {            $data['issued_by'] = $issuedBy;        }        return $this->update($id, $data);    }    public function revokeCertificate(int $id, string $reason): bool    {        return $this->update($id, ['status' => 'revoked', 'revoked_at' => now(), 'revocation_reason' => $reason]);    }    public function searchCertificates(string $keyword): Collection    {        return $this->query()->where('certificate_no', 'like', "%{$keyword}%")->orWhere('remarks', 'like', "%{$keyword}%")->get();    }    public function generateCertificateNo(): string    {        $last = $this->query()->whereYear('created_at', now()->year)->orderBy('id', 'desc')->first();        $nextNumber = $last ? ((int) substr($last->certificate_no, -5)) + 1 : 1;        return 'CERT-' . now()->year . '-' . str_pad($nextNumber, 5, '0', STR_PAD_LEFT);    }}